sql:
SELECT year 
FROM climate_years 
WHERE year_open > 0;

SELECT year_change
FROM climate_years
ORDER BY year DESC;

SELECT year, year_open
FROM climate_years
ORDER BY year ASC;

SELECT AVG(year_average) AS average_temperature
FROM climate_years
WHERE data_quality_score = (SELECT MAX(data_quality_score) FROM climate_years);

SELECT COUNT(*) AS number_of_reports
FROM analysis_reports
WHERE created_date LIKE '2023-06-%';

SELECT region_id, AVG(year_average) AS average_temperature
FROM climate_years
GROUP BY region_id;

SELECT AVG(year_open) AS avg_open, AVG(year_close) AS avg_close
FROM climate_years
WHERE region_id = 1;

SELECT year, year_average AS average_value
FROM climate_years
ORDER BY year ASC;

SELECT AVG(years.data_quality_score) AS average_data_quality_score
FROM climate_years AS years
INNER JOIN climate_data_sets AS datasets ON years.year_id = datasets.year_id;

SELECT AVG(data_quality_score) AS average_data_quality_score
FROM climate_years
WHERE region_id = 1;

SELECT MAX(year_max) AS max_value
FROM climate_years
WHERE year = 2020;
